import { DIDDocument } from 'did-resolver';

type ContextDocument = {
    '@context': Record<string, any>;
} & Record<string, any>;
type Document = ContextDocument | DIDDocument;
type DocumentLoaderObject = {
    contextUrl: string | null;
    document: Document;
    documentUrl: string;
};
type DocumentLoader = (url: string) => Promise<DocumentLoaderObject>;

export type { ContextDocument, Document, DocumentLoader, DocumentLoaderObject };
